class Solution:
    def findTheLongestBalancedSubstring(self, s):
        n = len(s)
        best = 0
        for i in range(n):
            for j in range(i, n):
                sub = s[i:j + 1]
                zeros = sub.count('0')
                ones = sub.count('1')
                if zeros == ones and sub == '0' * zeros + '1' * ones:
                    if len(sub) > best:
                        best = len(sub)
        return best

