class Solution:
    def findTheLongestBalancedSubstring(self, s):
        n = len(s)
        best = 0
        i = 0
        while i < n:
            zeros = 0
            while i < n and s[i] == '0':
                zeros += 1
                i += 1
            ones = 0
            while i < n and s[i] == '1':
                ones += 1
                i += 1
            best = max(best, 2 * min(zeros, ones))
        return best

