var findTheLongestBalancedSubstring = function(s) {
    const n = s.length;
    let best = 0;
    let i = 0;
    while (i < n) {
        let zeros = 0;
        while (i < n && s[i] === '0') { zeros++; i++; }
        let ones = 0;
        while (i < n && s[i] === '1') { ones++; i++; }
        best = Math.max(best, 2 * Math.min(zeros, ones));
    }
    return best;
};
